import{_ as e,o as i,c as l,a0 as o}from"./chunks/framework.CSGB4SNl.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/java-jucday01.md","filePath":"java/eight-legged essay/java-jucday01.md"}'),t={name:"java/eight-legged essay/java-jucday01.md"};function r(s,a,d,c,n,u){return i(),l("div",null,[...a[0]||(a[0]=[o('<h4 id="java中的线程安全是什么意思" tabindex="-1">java中的线程安全是什么意思 <a class="header-anchor" href="#java中的线程安全是什么意思" aria-label="Permalink to &quot;java中的线程安全是什么意思&quot;">​</a></h4><ol><li>安全的情况就是多个线程访问同一数据或执行同一代码时，不会出现数据不一致或逻辑错乱等问题</li><li>不安全就比如：两个线程，都自增100，最后结果不是200，因为两个线程可能同时读到旧值，各自加一写回就少了</li><li>解决方法：互斥锁、一个线程访问，ThreadLocal：每个线程持有自己的变量副本，数据不共享，final修饰不可变只能读不能改，原子操作使用原子类底层CAS指令实现无锁操作</li></ol><h4 id="事务的acid特性" tabindex="-1">事务的ACID特性 <a class="header-anchor" href="#事务的acid特性" aria-label="Permalink to &quot;事务的ACID特性&quot;">​</a></h4><ol><li>原子、一致、隔离、持久</li><li>原子：操作要么全成功要么全失败、一个事务执行期间发生故障，可将其回滚到之前的某一个版本</li><li>一致：数据在操作过程中可以处于中间状态，但是事务完成后必须得是确定的值，保证其一致性</li><li>隔离：各事务间的操作必须隔离，不能互相影响，隔离级别不同会影响数据一致性，如出现读未提交的脏读、不可重复读、幻读等</li><li>持久：事务执行完成后必须将数据持久化到数据库中，即使系统宕机也能保存下来</li></ol><h4 id="autowired和-resource区别" tabindex="-1">@Autowired和@Resource区别 <a class="header-anchor" href="#autowired和-resource区别" aria-label="Permalink to &quot;@Autowired和@Resource区别&quot;">​</a></h4><ol><li>@Autowired按照类型进行自动装配，如果多个同类型Bean则@Qualifier显式指定</li><li>@Resource按照属性名称进行装配，如果需要按照Bean的名称则可以显式指定其中的name属性</li></ol><h4 id="索引失效" tabindex="-1">索引失效 <a class="header-anchor" href="#索引失效" aria-label="Permalink to &quot;索引失效&quot;">​</a></h4><ol><li>左或左右模糊匹配-因为mysql采用最左匹配原则，且左模糊会走全表扫描、索引列使用函数/查询条件使用函数/计算、OR前是索引列，OR后不是索引列、NotExists关键字、ORDER BY/WHRER没有遵循最左匹配</li></ol>',8)])])}const m=e(t,[["render",r]]);export{_ as __pageData,m as default};
